import os

html_start = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>Alan Universal Writing System - Live Practice</title>\n<link href="https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;700&display=swap" rel="stylesheet">\n<style>\n  body {\n    background-color: #0b0e13;\n    color: #c8cdd6;\n    font-family: \'JetBrains Mono\', monospace;\n    display: flex;\n    flex-direction: column;\n    align-items: center;\n    justify-content: flex-start;\n    min-height: 100vh;\n    margin: 0;\n    padding: 20px 20px 60px 20px; /* Enhanced bottom padding to prevent legend cutoff */\n    box-sizing: border-box;\n    overflow-y: auto;\n  }\n  \n  .header {\n    text-align: center;\n    margin-bottom: 20px;\n    width: 100%;\n    max-width: 850px;\n    display: flex;\n    align-items: center;\n    justify-content: space-between;\n  }\n  \n  .header h1 {\n    font-size: 22px;\n    color: #fff;\n    margin: 0;\n    display: flex;\n    align-items: center;\n    gap: 10px;\n  }\n\n  .header a {\n    color: #48b5c4;\n    text-decoration: none;\n    border-bottom: 1px dashed #48b5c4;\n    font-size: 14px;\n    transition: all 0.2s ease;\n  }\n  .header a:hover {\n    color: #7fcf9f;\n    border-color: #7fcf9f;\n  }\n\n  /* Two Identical Large Boxes styled exactly like Output Display */\n  .box-container {\n    display: flex;\n    flex-direction: column;\n    gap: 20px;\n    width: 100%;\n    max-width: 850px;\n    margin-bottom: 25px;\n    box-sizing: border-box;\n  }\n\n  .row-layout {\n    display: flex;\n    align-items: center;\n    gap: 15px;\n    width: 100%;\n  }\n\n  /* English Input Box */\n  .english-box {\n    flex-grow: 1;\n    min-height: 140px;\n    max-height: 200px;\n    background: #090c11;\n    border: 1px solid #2b3340;\n    border-radius: 12px;\n    padding: 15px;\n    box-sizing: border-box;\n    box-shadow: inset 0 4px 15px rgba(0,0,0,0.6);\n  }\n\n  .english-box textarea {\n    width: 100%;\n    height: 100%;\n    min-height: 110px;\n    background: transparent;\n    border: none;\n    outline: none;\n    color: #fff;\n    font-family: \'JetBrains Mono\', monospace;\n    font-size: 15px;\n    resize: none;\n    box-sizing: border-box;\n    line-height: 1.6;\n  }\n\n  /* Redesigned Translate Button in Pure Alan (using sai / say communication symbol) */\n  .translate-btn {\n    background: #48b5c4;\n    color: #0b0e13;\n    border: none;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    width: 54px;\n    height: 54px;\n    border-radius: 12px;\n    cursor: pointer;\n    flex-shrink: 0;\n    transition: all 0.2s ease;\n    box-shadow: 0 4px 14px rgba(0,0,0,0.3);\n  }\n  .translate-btn:hover {\n    transform: scale(1.05);\n    box-shadow: 0 4px 12px rgba(72,181,196,0.4);\n  }\n\n  /* Alan Output Display Box (Identical Styling to English Input Box) */\n  .output-display {\n    flex-grow: 1;\n    display: flex;\n    flex-direction: column;\n    align-items: stretch;\n    justify-content: flex-start;\n    min-height: 140px;\n    max-height: 200px;\n    overflow-y: auto;\n    background: #090c11;\n    border: 1px solid #2b3340;\n    border-radius: 12px;\n    padding: 15px;\n    box-sizing: border-box;\n    box-shadow: inset 0 4px 15px rgba(0,0,0,0.6);\n  }\n\n  /* Symmetrical Guidance Display */\n  .guidance-panel {\n    display: none;\n    background: #161b24;\n    border: 1px solid #2b3340;\n    border-radius: 12px;\n    width: 100%;\n    max-width: 850px;\n    padding: 20px;\n    margin-bottom: 20px;\n    box-sizing: border-box;\n    box-shadow: 0 10px 30px rgba(0,0,0,0.4);\n    animation: slide-down 0.3s ease;\n  }\n  @keyframes slide-down {\n    from { opacity: 0; transform: translateY(-5px); }\n    to { opacity: 1; transform: translateY(0); }\n  }\n\n  .instructions {\n    font-size: 14px;\n    line-height: 1.6;\n    color: #d6dae2;\n    margin-bottom: 15px;\n  }\n\n  .hint-box {\n    background: rgba(72, 181, 196, 0.1);\n    border-left: 4px solid #48b5c4;\n    padding: 10px 15px;\n    font-size: 13px;\n    color: #a7ddec;\n    border-radius: 0 8px 8px 0;\n    margin-bottom: 15px;\n  }\n\n  /* Non-blocking success banner */\n  .success-banner {\n    display: none;\n    padding: 12px 15px;\n    background: rgba(127, 207, 159, 0.12);\n    border-left: 4px solid #7fcf9f;\n    border-radius: 4px;\n    color: #a6f2be;\n    font-size: 14px;\n    margin-bottom: 15px;\n    align-items: center;\n    justify-content: space-between;\n  }\n\n  .btn-next {\n    background: #7fcf9f;\n    color: #0b0e13;\n    border: none;\n    padding: 8px 16px;\n    font-family: \'JetBrains Mono\', monospace;\n    font-weight: bold;\n    font-size: 13px;\n    border-radius: 6px;\n    cursor: pointer;\n    transition: all 0.2s ease;\n  }\n  .btn-next:hover {\n    transform: scale(1.05);\n  }\n\n  .line {\n    display: flex;\n    align-items: center;\n    gap: 12px;\n    min-height: 40px;\n    margin-top: 4px;\n    border-left: 2px solid transparent;\n    transition: all 0.2s ease;\n    box-sizing: border-box;\n  }\n  .line[data-indent="1"] { border-left-color: #2b3340; }\n  .line[data-indent="2"] { border-left-color: #3d4757; }\n  .line[data-indent="3"] { border-left-color: #4a5669; }\n  .line[data-indent="4"] { border-left-color: #5a6980; }\n\n  .line .spacer {\n    width: 16px;\n    height: 32px;\n    flex-shrink: 0;\n    position: relative;\n  }\n  .line .spacer::after {\n    content: \'·\';\n    color: #ffffff;\n    position: absolute;\n    left: 50%;\n    top: 50%;\n    transform: translate(-50%, -50%);\n    font-size: 20px;\n    font-weight: bold;\n  }\n\n  .line svg {\n    width: 28px;\n    height: 28px;\n    stroke: #e2e8f0;\n  }\n\n  .cursor {\n    width: 2px;\n    height: 28px;\n    background: #48b5c4;\n    animation: blink-anim 1s step-end infinite;\n  }\n  \n  @keyframes blink-anim { 50% { opacity: 0; } }\n\n  /* Keyboard Style */\n  .split-keyboard {\n    display: flex;\n    justify-content: center;\n    gap: 30px;\n    align-items: flex-end;\n  }\n\n  .half {\n    background: #161b24;\n    padding: 20px;\n    border-radius: 16px;\n    border: 1px solid #2b3340;\n    box-shadow: 0 15px 30px rgba(0,0,0,0.5), inset 0 1px 0 rgba(255,255,255,0.05);\n    display: flex;\n    flex-direction: column;\n    gap: 8px;\n  }\n\n  .half.left { transform: rotate(2deg); }\n  .half.right { transform: rotate(-2deg); }\n\n  .row {\n    display: flex;\n    gap: 6px;\n    justify-content: center;\n  }\n\n  /* Pristine 3D Rounded Square Keycaps */\n  .key {\n    width: 48px;\n    height: 48px;\n    background: linear-gradient(180deg, #2b3340 0%, #1e2430 100%);\n    border-radius: 8px;\n    border: 1px solid #0b0e13;\n    box-shadow: 0 4px 0 #0b0e13, inset 0 1px 1px rgba(255,255,255,0.1);\n    display: flex;\n    flex-direction: column;\n    align-items: center;\n    justify-content: center;\n    position: relative;\n    cursor: pointer;\n    transition: all 0.1s ease;\n  }\n  \n  .key:active {\n    transform: translateY(4px);\n    box-shadow: 0 0px 0 #0b0e13, inset 0 1px 2px rgba(0,0,0,0.5);\n  }\n\n  .key svg {\n    width: 20px;\n    height: 20px;\n    stroke: #e2e8f0;\n  }\n  \n  .key .handle {\n    position: absolute;\n    bottom: 3px;\n    font-size: 8px;\n    color: #5d626c;\n    letter-spacing: 0.05em;\n  }\n  \n  /* Category Colors */\n  .key.entity { border-top: 2px solid #7fcf9f; }\n  .key.action { border-top: 2px solid #ff8a6b; }\n  .key.mental { border-top: 2px solid #a388ed; }\n  .key.space  { border-top: 2px solid #8aa6d4; }\n  .key.desc   { border-top: 2px solid #f67280; }\n  .key.logic  { border-top: 2px solid #ffd166; }\n  .key.time   { border-top: 2px solid #48b5c4; }\n  .key.num    { border-top: 2px solid #e2e8f0; }\n\n  .key.wide { width: 75px; }\n  .key.tall { height: 104px; }\n  \n  .thumb-cluster {\n    display: flex;\n    gap: 8px;\n    margin-top: 8px;\n  }\n  .thumb-cluster.left { justify-content: flex-end; padding-right: 10px; }\n  .thumb-cluster.right { justify-content: flex-start; padding-left: 10px; }\n\n  /* Symmetrical 3x3 Compass D-Pad */\n  .compass-cross {\n    display: grid;\n    grid-template-columns: repeat(3, 36px);\n    grid-template-rows: repeat(3, 36px);\n    gap: 4px;\n    align-items: center;\n    justify-content: center;\n  }\n\n  /* Highlighting Pulsing key */\n  .key.highlight {\n    animation: pulse-border 1.5s infinite alternate;\n    box-shadow: 0 0 15px rgba(72,181,196,0.8);\n    border-color: #48b5c4 !important;\n    background: #1c2b3d !important;\n  }\n  @keyframes pulse-border {\n    0% { transform: scale(1); }\n    100% { transform: scale(1.05); background: #22384a; }\n  }\n\n  /* Symmetrical Top, Bottom, and Left Bar Negation Modifier */\n  .anti-bar {\n    display: none;\n    opacity: 0;\n  }\n  .flipped .key[data-flip] .anti-bar {\n    display: block !important;\n    opacity: 1 !important;\n  }\n\n  .key.modifier.active {\n    background: #2b384a;\n    box-shadow: inset 0 2px 4px rgba(0,0,0,0.8);\n    border-top-color: #a388ed !important;\n  }\n\n  /* Responsive Design */\n  @media (max-width: 1000px) {\n    .split-keyboard {\n      gap: 20px;\n      transform: scale(0.85);\n    }\n  }\n\n  .legend {\n    display: flex;\n    flex-wrap: wrap;\n    justify-content: center;\n    gap: 15px;\n    margin-top: 30px;\n    font-size: 12px;\n    max-width: 800px;\n  }\n  .legend-item { display: flex; align-items: center; gap: 6px; }\n  .dot { width: 10px; height: 10px; border-radius: 50%; }\n</style>\n</head>\n<body>\n\n<div class="header">\n  <h1>\n    <span style="display:inline-block; position:relative; width:1.1em; height:1.1em; vertical-align:-0.2em;"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="position:absolute; top:0; left:0; width:100%; height:100%;"><polygon points="12,2 22,9 18,20 6,20 2,9" /></svg><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="position:absolute; top:0; left:0; width:100%; height:100%; transform:scale(0.5); transform-origin: center;"><rect x="9" y="8" width="6" height="8" fill="currentColor" /></svg></span>\n    Alan: Live Practice\n  </h1>\n  <div style="display:flex; gap:15px;">\n    <a href="tutorial.html">Switch to Tutorial App &rarr;</a>\n    <a href="keyboard_prototype.html">Back to Sandbox &rarr;</a>\n  </div>\n</div>\n\n<div class="box-container">\n  <!-- Row 1: English Input Display + Standalone Translate Button -->\n  <div class="row-layout">\n    <div class="english-box">\n      <textarea id="spellcheckInput" placeholder="Type or paste your English sentence here... (e.g., \'update customer 867 set balance to 500\')"></textarea>\n    </div>\n    \n    <!-- Standalone Translate Button in Pure Alan (using sai / say communication symbol) -->\n    <button class="translate-btn" id="spellcheckBtn" title="Translate &amp; Verify (Alan say symbol)">\n      <svg viewBox="0 0 24 24" fill="none" stroke="#0b0e13" stroke-width="3.5" style="width: 24px; height: 24px;"><polygon points="8,4 8,20 20,12" /></svg>\n    </button>\n  </div>\n\n  <!-- Row 2: Alan Output Display (Symmetrically aligned via blank spacer) -->\n  <div class="row-layout">\n    <div class="output-display" id="output">\n      <div class="line" data-indent="0">\n        <div class="cursor" id="cursor"></div>\n      </div>\n    </div>\n    \n    <!-- Invisible spacer of identical size as Translate Button for perfect sub-pixel width symmetry -->\n    <div style="width: 54px; height: 54px; flex-shrink: 0;"></div>\n  </div>\n</div>\n\n<!-- Symmetrical Guidance Box -->\n<div class="guidance-panel" id="guidancePanel">\n  <div class="success-banner" id="successBanner">\n    <span>✓ Perfect representation! Feel free to play around, or type a new sentence above.</span>\n    <button class="btn-next" id="btnReset">Reset Output</button>\n  </div>\n\n  <div class="instructions" id="lessonInstructions">\n    Heuristic Translation loaded successfully! Let\'s type it using the split-keyboard below.\n  </div>\n\n  <div class="checklist" id="checklist" style="display: flex; flex-direction: column; gap: 8px; margin-bottom: 15px; font-size: 13px; color: #8aa6d4;"></div>\n\n  <div class="hint-box" id="lessonHint">\n    Hint: Follow the flashing keys on the keyboard to map your English sentence to Alan\'s vertical cascades!\n  </div>\n</div>\n\n<div class="split-keyboard">\n\n  <!-- LEFT HALF: Logic, Mental, Entities, Time -->\n  <div class="half left">\n    <!-- Row 0: Numbers -->\n    <div class="row" style="padding-left: 20px;">\n      <div class="key num" data-handle="1"><svg viewBox="0 0 24 24"><text x="12" y="16" font-family="monospace" font-size="16" font-weight="bold" text-anchor="middle" fill="#e2e8f0">1</text></svg><span class="handle">1</span></div>\n      <div class="key num" data-handle="2"><svg viewBox="0 0 24 24"><text x="12" y="16" font-family="monospace" font-size="16" font-weight="bold" text-anchor="middle" fill="#e2e8f0">2</text></svg><span class="handle">2</span></div>\n      <div class="key num" data-handle="3"><svg viewBox="0 0 24 24"><text x="12" y="16" font-family="monospace" font-size="16" font-weight="bold" text-anchor="middle" fill="#e2e8f0">3</text></svg><span class="handle">3</span></div>\n      <div class="key num" data-handle="4"><svg viewBox="0 0 24 24"><text x="12" y="16" font-family="monospace" font-size="16" font-weight="bold" text-anchor="middle" fill="#e2e8f0">4</text></svg><span class="handle">4</span></div>\n      <div class="key num" data-handle="5"><svg viewBox="0 0 24 24"><text x="12" y="16" font-family="monospace" font-size="16" font-weight="bold" text-anchor="middle" fill="#e2e8f0">5</text></svg><span class="handle">5</span></div>\n      <div class="key num" data-handle="add"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><line x1="12" y1="5" x2="12" y2="19" stroke-width="3" /><line x1="5" y1="12" x2="19" y2="12" stroke-width="3" /></svg><span class="handle">add</span></div>\n      <div class="key num" data-handle="sub"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><line x1="5" y1="12" x2="19" y2="12" stroke-width="3" /></svg><span class="handle">sub</span></div>\n    </div>\n    <!-- Row 1: Logic -->\n    <div class="row" style="padding-left: 0px;">\n      <div class="key logic" data-handle="not"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><rect x="4" y="4" width="16" height="16" /><line x1="4" y1="4" x2="20" y2="20" /></svg><span class="handle">not</span></div>\n      <div class="key logic" data-handle="if"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M 12 20 V 12 L 6 4 M 12 12 L 18 4" /></svg><span class="handle">if</span></div>\n      <div class="key logic" data-handle="can"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M 12 4 A 6 6 0 0 1 18 10 V 20 M 12 4 A 6 6 0 0 0 6 10 V 12 M 6 16 V 20" /></svg><span class="handle">can</span></div>\n      <div class="key logic" data-handle="may"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M 6 12 Q 9 6 12 12 T 18 12" /></svg><span class="handle">may</span></div>\n      <div class="key logic" data-handle="bik"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M 12 4 V 12 L 6 20 M 12 12 L 18 20" /></svg><span class="handle">cause</span></div>\n      <div class="key logic" data-handle="is"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><line x1="9" y1="4" x2="9" y2="20" stroke-width="3" /><line x1="15" y1="4" x2="15" y2="20" stroke-width="3" /></svg><span class="handle">be</span></div>\n      <div class="key logic" data-handle="and"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="6,18 12,6 18,18" stroke-width="3" stroke-linecap="round" stroke-linejoin="round" /></svg><span class="handle">and</span></div>\n      <div class="key logic" data-handle="or"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="6,6 12,18 18,6" stroke-width="3" stroke-linecap="round" stroke-linejoin="round" /></svg><span class="handle">or</span></div>\n      <div class="key logic" data-handle="andor"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="6,18 12,6 18,18" stroke-width="3" stroke-linecap="round" stroke-linejoin="round" /><polyline points="6,6 12,18 18,6" stroke-width="3" stroke-linecap="round" stroke-linejoin="round" /></svg><span class="handle">andor</span></div>\n    </div>\n    <!-- Row 2: Mental -->\n    <div class="row" style="padding-left: 20px;">\n      <div class="key mental" data-handle="think"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polygon points="12,2 22,12 12,22 2,12" /><circle cx="12" cy="12" r="2" fill="#e2e8f0" /></svg><span class="handle">think</span></div>\n      <div class="key mental" data-handle="know"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polygon points="12,2 22,12 12,22 2,12" fill="#e2e8f0"/></svg><span class="handle">know</span></div>\n      <div class="key mental" data-handle="want"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polygon points="12,2 22,12 12,22 2,12" /><line x1="12" y1="12" x2="24" y2="12" /><polyline points="20,8 24,12 20,16" /></svg><span class="handle">want</span></div>\n      <div class="key mental" data-handle="feel"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polygon points="12,2 22,12 12,22 2,12" /><path d="M 8 12 Q 10 8 12 12 T 16 12" /></svg><span class="handle">feel</span></div>\n      <div class="key mental" data-handle="see"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polygon points="12,2 22,12 12,22 2,12" /><path d="M 7 12 Q 12 7 17 12 Q 12 17 7 12" /></svg><span class="handle">see</span></div>\n      <div class="key mental" data-handle="hear"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polygon points="12,2 22,12 12,22 2,12" /><path d="M 12 8 A 4 4 0 0 1 12 16 M 9 10 A 2 2 0 0 1 9 14" /></svg><span class="handle">hear</span></div>\n    </div>\n    <!-- Row 3: Entities -->\n    <div class="row" style="padding-left: 10px;">\n      <div class="key entity" data-handle="me"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><circle cx="12" cy="12" r="10" /><circle cx="12" cy="12" r="4" fill="#e2e8f0" /></svg><span class="handle">me</span></div>\n      <div class="key entity" data-handle="you"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><circle cx="12" cy="12" r="10" /><circle cx="12" cy="12" r="4" /></svg><span class="handle">you</span></div>\n      <div class="key entity" data-handle="someone"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><circle cx="12" cy="12" r="10" /></svg><span class="handle">someone</span></div>\n      <div class="key entity" data-handle="something"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><circle cx="12" cy="12" r="10" /><line x1="6" y1="12" x2="18" y2="12" /></svg><span class="handle">thing</span></div>\n      <div class="key entity" data-handle="people"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><circle cx="12" cy="12" r="10" /><circle cx="12" cy="7" r="1.5" fill="#e2e8f0"/><circle cx="8" cy="14" r="1.5" fill="#e2e8f0"/><circle cx="16" cy="14" r="1.5" fill="#e2e8f0"/></svg><span class="handle">people</span></div>\n      <div class="key entity" data-handle="body"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><circle cx="12" cy="12" r="10" /><line x1="12" y1="2" x2="12" y2="22" /></svg><span class="handle">body</span></div>\n    </div>\n    <!-- Row 4: Time -->\n    <div class="row" style="padding-left: 30px;">\n      <div class="key time" data-handle="time"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><line x1="2" y1="12" x2="22" y2="12" /><line x1="12" y1="8" x2="12" y2="16" /></svg><span class="handle">time</span></div>\n      <div class="key time" data-handle="now"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><line x1="2" y1="12" x2="22" y2="12" /><line x1="12" y1="6" x2="12" y2="18" stroke-width="4" /></svg><span class="handle">now</span></div>\n      <div class="key time" data-handle="before" data-flip="left"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><line x1="8" y1="12" x2="24" y2="12" /><line x1="14" y1="8" x2="14" y2="16" /><polyline points="12,12 8,12" /><polyline points="10,10 8,12 10,14" /></svg><span class="anti-bar" x1="4" y1="2" x2="20" y2="2" stroke="#ff8a6b" stroke-width="3" stroke-linecap="round"></span><span class="handle">before</span></div>\n      <div class="key time" data-handle="long"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><line x1="4" y1="12" x2="20" y2="12" /><polyline points="6,9 2,12 6,15" /><polyline points="18,9 22,12 18,15" /></svg><span class="handle">long</span></div>\n      <div class="key time" data-handle="moment"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><line x1="12" y1="6" x2="12" y2="18" stroke-width="4" /></svg><span class="handle">moment</span></div>\n    </div>\n    <!-- Left Thumb Cluster -->\n    <div class="thumb-cluster left" style="align-items: center; gap: 15px;">\n      <div class="key wide modifier" data-action="FLIP" style="color: #ffd166; font-size: 16px; font-weight: bold;" title="Hold/Toggle to flip symbols to opposites">⇿ ANTI</div>\n      \n      <!-- Symmetrical Cross D-Pad (Left Half) -->\n      <div class="compass-cross">\n        <div></div>\n        <div class="key space" data-handle="above" data-flip="below" style="width:36px; height:36px;" title="Above">\n          <svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="8,14 12,9 16,14" /></svg>\n        </div>\n        <div></div>\n        \n        <div class="key space" data-handle="left" data-flip="left" style="width:36px; height:36px;" title="Left">\n          <svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="14,8 9,12 14,16" /></svg>\n        </div>\n        <div class="key space" data-handle="in" data-flip="above" style="width:36px; height:36px;" title="Inside">\n          <!-- Compass star in the center not a dot -->\n          <svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polygon points="12,6 13.5,11 18,12 13.5,13 12,18 10.5,13 6,12 10.5,11" fill="#e2e8f0" stroke="none" /></svg>\n        </div>\n        <div class="key space" data-handle="right" data-flip="left" style="width:36px; height:36px;" title="Right">\n          <svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="10,8 15,12 10,16" /></svg>\n        </div>\n        \n        <div></div>\n        <div class="key space" data-handle="below" data-flip="below" style="width:36px; height:36px;" title="Below">\n          <svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="8,10 12,15 16,10" /></svg>\n        </div>\n        <div></div>\n      </div>\n\n      <div class="key tall space" data-action="SPACE" title="Space (Horizontal Word Gap)"><svg viewBox="0 0 24 24" fill="none" stroke="#8aa6d4" stroke-width="2"><path d="M 4 8 V 16 H 20 V 8" stroke-width="3" /></svg><span class="handle">space</span></div>\n      <div class="key tall action" data-action="INDENT" title="Step Right (Indent)"><svg viewBox="0 0 24 24" fill="none" stroke="#7fcf9f" stroke-width="2"><line x1="4" y1="12" x2="20" y2="12" stroke-width="3" /><polyline points="14,6 20,12 14,18" stroke-width="3" /></svg><span class="handle">indent</span></div>\n    </div>\n  </div>\n\n\n  <!-- RIGHT HALF: Quantifiers, Actions, Descriptors, Space -->\n  <div class="half right">\n    <!-- Row 0: Numbers -->\n    <div class="row" style="padding-right: 20px;">\n      <div class="key num" data-handle="6"><svg viewBox="0 0 24 24"><text x="12" y="16" font-family="monospace" font-size="16" font-weight="bold" text-anchor="middle" fill="#e2e8f0">6</text></svg><span class="handle">6</span></div>\n      <div class="key num" data-handle="7"><svg viewBox="0 0 24 24"><text x="12" y="16" font-family="monospace" font-size="16" font-weight="bold" text-anchor="middle" fill="#e2e8f0">7</text></svg><span class="handle">7</span></div>\n      <div class="key num" data-handle="8"><svg viewBox="0 0 24 24"><text x="12" y="16" font-family="monospace" font-size="16" font-weight="bold" text-anchor="middle" fill="#e2e8f0">8</text></svg><span class="handle">8</span></div>\n      <div class="key num" data-handle="9"><svg viewBox="0 0 24 24"><text x="12" y="16" font-family="monospace" font-size="16" font-weight="bold" text-anchor="middle" fill="#e2e8f0">9</text></svg><span class="handle">9</span></div>\n      <div class="key num" data-handle="0"><svg viewBox="0 0 24 24"><text x="12" y="16" font-family="monospace" font-size="16" font-weight="bold" text-anchor="middle" fill="#e2e8f0">0</text></svg><span class="handle">0</span></div>\n      <div class="key num" data-handle="mul"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><line x1="6" y1="6" x2="18" y2="18" stroke-width="3" /><line x1="18" y1="6" x2="6" y2="18" stroke-width="3" /></svg><span class="handle">mul</span></div>\n      <div class="key num" data-handle="div"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><line x1="5" y1="12" x2="19" y2="12" stroke-width="3" /><circle cx="12" cy="6" r="2" fill="#e2e8f0" /><circle cx="12" cy="18" r="2" fill="#e2e8f0" /></svg><span class="handle">div</span></div>\n      <div class="key num" data-handle="eql"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><line x1="5" y1="9" x2="19" y2="9" stroke-width="3" /><line x1="5" y1="15" x2="19" y2="15" stroke-width="3" /></svg><span class="handle">eql</span></div>\n    </div>\n    <!-- Row 1: Quantifiers -->\n    <div class="row" style="padding-right: 0px;">\n      <div class="key logic" data-handle="one"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><circle cx="12" cy="12" r="2" fill="#e2e8f0" /></svg><span class="handle">one</span></div>\n      <div class="key logic" data-handle="two"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><circle cx="8" cy="12" r="2" fill="#e2e8f0" /><circle cx="16" cy="12" r="2" fill="#e2e8f0" /></svg><span class="handle">two</span></div>\n      <div class="key logic" data-handle="few"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><circle cx="12" cy="8" r="1.5" fill="#e2e8f0" /><circle cx="7" cy="15" r="1.5" fill="#e2e8f0" /><circle cx="17" cy="15" r="1.5" fill="#e2e8f0" /></svg><span class="handle">few</span></div>\n      <div class="key logic" data-handle="som"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><circle cx="12" cy="12" r="10" stroke-dasharray="4,4" /></svg><span class="handle">some</span></div>\n      <div class="key logic" data-handle="mor"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><circle cx="6" cy="6" r="1.5" fill="#e2e8f0" /><circle cx="12" cy="6" r="1.5" fill="#e2e8f0" /><circle cx="18" cy="6" r="1.5" fill="#e2e8f0" /><circle cx="6" cy="12" r="1.5" fill="#e2e8f0" /><circle cx="12" cy="12" r="1.5" fill="#e2e8f0" /><circle cx="18" cy="12" r="1.5" fill="#e2e8f0" /><circle cx="6" cy="18" r="1.5" fill="#e2e8f0" /><circle cx="12" cy="18" r="1.5" fill="#e2e8f0" /><circle cx="18" cy="18" r="1.5" fill="#e2e8f0" /></svg><span class="handle">more</span></div>\n      <div class="key logic" data-handle="al"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><circle cx="12" cy="12" r="10" fill="#e2e8f0" /></svg><span class="handle">all</span></div>\n    </div>\n    <!-- Row 2: Actions & Comm -->\n    <div class="row" style="padding-right: 20px;">\n      <div class="key action" data-handle="do"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polygon points="12,2 2,20 22,20" /></svg><span class="handle">do</span></div>\n      <div class="key action" data-handle="mov"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><line x1="4" y1="12" x2="20" y2="12" /><polyline points="10,6 4,12 10,18" /><polyline points="14,6 20,12 14,18" /></svg><span class="handle">move</span></div>\n      <div class="key action" data-handle="liv" data-flip="above"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polygon points="12,6 2,22 22,22" /><circle cx="12" cy="16" r="2" fill="#e2e8f0"/></svg><span class="anti-bar" x1="4" y1="2" x2="20" y2="2" stroke="#ff8a6b" stroke-width="3" stroke-linecap="round"></span><span class="handle">live</span></div>\n      <div class="key action" data-handle="sai"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polygon points="8,4 8,20 20,12" /></svg><span class="handle">say</span></div>\n      <div class="key action" data-handle="wrd"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><circle cx="12" cy="12" r="10" /><line x1="8" y1="9" x2="16" y2="9" /><line x1="8" y1="12" x2="16" y2="12" /><line x1="8" y1="15" x2="12" y2="15" /></svg><span class="handle">words</span></div>\n    </div>\n    <!-- Row 3: Descriptors -->\n    <div class="row" style="padding-right: 10px;">\n      <div class="key desc" data-handle="gud" data-flip="above"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><rect x="4" y="6" width="16" height="16" /><polyline points="8,14 12,9 16,14" /></svg><span class="anti-bar" x1="4" y1="2" x2="20" y2="2" stroke="#ff8a6b" stroke-width="3" stroke-linecap="round"></span><span class="handle">good</span></div>\n      <div class="key desc" data-handle="big" data-flip="above"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><rect x="4" y="6" width="16" height="16" /><polygon points="8,18 16,18 18,9 6,9" fill="#e2e8f0" /></svg><span class="anti-bar" x1="4" y1="2" x2="20" y2="2" stroke="#ff8a6b" stroke-width="3" stroke-linecap="round"></span><span class="handle">big</span></div>\n      <div class="key desc" data-handle="les" data-flip="left"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="15,5 9,12 15,19" stroke-width="3" stroke-linecap="round" stroke-linejoin="round" /></svg><span class="anti-bar" x1="4" y1="2" x2="20" y2="2" stroke="#ff8a6b" stroke-width="3" stroke-linecap="round"></span><span class="handle">less</span></div>\n      <div class="key desc" data-handle="tru" data-flip="above"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><rect x="4" y="6" width="16" height="16" fill="#e2e8f0" /></svg><span class="anti-bar" x1="4" y1="2" x2="20" y2="2" stroke="#ff8a6b" stroke-width="3" stroke-linecap="round"></span><span class="handle">true</span></div>\n      <div class="key desc" data-handle="lik"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><rect x="4" y="4" width="16" height="16" /><polyline points="8,13 12,8 16,13" /><polyline points="8,18 12,13 16,18" /></svg><span class="handle">like</span></div>\n      <div class="key desc" data-handle="part"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><rect x="4" y="4" width="12" height="12" /><rect x="8" y="8" width="12" height="12" /></svg><span class="handle">part</span></div>\n    </div>\n    <!-- Row 4: Space -->\n    <div class="row" style="padding-right: 30px;">\n      <div class="key space" data-handle="place"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><line x1="2" y1="20" x2="22" y2="20" /><line x1="12" y1="20" x2="12" y2="2" /><circle cx="12" cy="12" r="3" fill="#e2e8f0" /></svg><span class="handle">place</span></div>\n      <div class="key space" data-handle="water"><svg viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M 3,8 Q 7.5,5 12,8 T 21,8 M 3,14 Q 7.5,11 12,14 T 21,14 M 3,20 Q 7.5,17 12,20 T 21,20" stroke="currentColor" stroke-width="2" stroke-linecap="round" fill="none" /></svg><span class="handle">water</span></div>\n    </div>\n    <!-- Right Thumb Cluster -->\n    <div class="thumb-cluster right" style="align-items: center; gap: 15px;">\n      <div class="key tall action" data-action="DOWN" title="Step Down (Newline / Sibling)"><svg viewBox="0 0 24 24" fill="none" stroke="#ff8a6b" stroke-width="2"><path d="M 20 6 V 14 H 6 M 12 8 L 6 14 L 12 20" stroke-width="3" stroke-linecap="round" stroke-linejoin="round" /></svg><span class="handle">down</span></div>\n      <div class="key tall action" data-action="OUTDENT" title="Step Left (Outdent)"><svg viewBox="0 0 24 24" fill="none" stroke="#7fcf9f" stroke-width="2"><line x1="20" y1="12" x2="4" y2="12" stroke-width="3" /><polyline points="10,6 4,12 10,18" stroke-width="3" /></svg><span class="handle">outdent</span></div>\n\n      <!-- Symmetrical Cross D-Pad (Right Half) -->\n      <div class="compass-cross">\n        <div></div>\n        <div class="key space" data-handle="above" data-flip="below" style="width:36px; height:36px;" title="Above">\n          <svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="8,14 12,9 16,14" /></svg>\n        </div>\n        <div></div>\n        \n        <div class="key space" data-handle="left" data-flip="left" style="width:36px; height:36px;" title="Left">\n          <svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="14,8 9,12 14,16" /></svg>\n        </div>\n        <div class="key space" data-handle="in" data-flip="above" style="width:36px; height:36px;" title="Inside">\n          <!-- Compass star in the center not a dot -->\n          <svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polygon points="12,6 13.5,11 18,12 13.5,13 12,18 10.5,13 6,12 10.5,11" fill="#e2e8f0" stroke="none" /></svg>\n        </div>\n        <div class="key space" data-handle="right" data-flip="left" style="width:36px; height:36px;" title="Right">\n          <svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="10,8 15,12 10,16" /></svg>\n        </div>\n        \n        <div></div>\n        <div class="key space" data-handle="below" data-flip="below" style="width:36px; height:36px;" title="Below">\n          <svg viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="8,10 12,15 16,10" /></svg>\n        </div>\n        <div></div>\n      </div>\n\n      <div class="key wide modifier" data-action="FLIP" style="color: #ffd166; font-size: 16px; font-weight: bold;" title="Hold/Toggle to flip symbols to opposites">⇿ ANTI</div>\n      <div class="key wide action" data-action="BACK" style="color: #f67280; font-size: 16px; font-weight: bold;" title="Backspace">⌫ BACK</div>\n    </div>\n  </div>\n\n</div>\n\n<div class="legend">\n  <div class="legend-item"><div class="dot" style="background: #e2e8f0;"></div> Numbers</div>\n  <div class="legend-item"><div class="dot" style="background: #7fcf9f;"></div> Entities (Substantives)</div>\n  <div class="legend-item"><div class="dot" style="background: #a388ed;"></div> Mental Predicates</div>\n  <div class="legend-item"><div class="dot" style="background: #ffd166;"></div> Logic &amp; Quantifiers</div>\n  <div class="legend-item"><div class="dot" style="background: #48b5c4;"></div> Time</div>\n  <div class="legend-item"><div class="dot" style="background: #ff8a6b;"></div> Actions (Events)</div>\n  <div class="legend-item"><div class="dot" style="background: #f67280;"></div> Descriptors</div>\n  <div class="legend-item"><div class="dot" style="background: #8aa6d4;"></div> Space &amp; Compass</div> <!-- Updated legend title -->\n</div>\n\n<script>\n  const output = document.getElementById(\'output\');\n  let activeLine = output.querySelector(\'.line\');\n  let cursor = document.getElementById(\'cursor\');\n  let currentIndent = 0;\n  let isFlipped = false;\n\n  const successBanner = document.getElementById(\'successBanner\');\n  const btnReset = document.getElementById(\'btnReset\');\n  const guidancePanel = document.getElementById(\'guidancePanel\');\n\n  const lessonInstructionsEl = document.getElementById(\'lessonInstructions\');\n  const lessonHintEl = document.getElementById(\'lessonHint\');\n  const checklistEl = document.getElementById(\'checklist\');\n\n  let currentStep = 0;\n  let sandboxConfig = null;\n\n  function resetWorkspace() {\n    output.innerHTML = \'<div class="line" data-indent="0"><div class="cursor" id="cursor"></div></div>\';\n    activeLine = output.querySelector(\'.line\');\n    cursor = document.getElementById(\'cursor\');\n    currentIndent = 0;\n    \n    currentStep = 0;\n    isFlipped = false;\n    document.querySelector(\'.split-keyboard\').classList.remove(\'flipped\');\n    document.querySelectorAll(\'.key[data-action="FLIP"]\').forEach(el => el.classList.remove(\'active\'));\n    \n    successBanner.style.display = \'none\';\n    highlightNextKey();\n    updateChecklist();\n  }\n\n  btnReset.addEventListener(\'click\', resetWorkspace);\n\n  function highlightNextKey() {\n    document.querySelectorAll(\'.key\').forEach(k => k.classList.remove(\'highlight\'));\n    \n    if (!sandboxConfig || currentStep >= sandboxConfig.targetKeys.length) return;\n    \n    const target = sandboxConfig.targetKeys[currentStep];\n    const keyEl = document.querySelector(`.key[data-action="${target}"]`) || \n                  document.querySelector(`.key[data-handle="${target}"]`);\n                \n    if (keyEl) {\n      keyEl.classList.add(\'highlight\');\n    }\n  }\n\n  function updateChecklist() {\n    if (!sandboxConfig) {\n      checklistEl.innerHTML = \'\';\n      return;\n    }\n    \n    checklistEl.innerHTML = \'\';\n    sandboxConfig.targetKeys.forEach((keyName, i) => {\n      const item = document.createElement(\'div\');\n      item.style.display = \'flex\';\n      item.style.alignItems = \'center\';\n      item.style.gap = \'8px\';\n      \n      const check = document.createElement(\'span\');\n      check.innerHTML = i < currentStep ? \'✓\' : \'○\';\n      check.style.color = i < currentStep ? \'#7fcf9f\' : \'#5d626c\';\n      check.style.fontWeight = \'bold\';\n      \n      const text = document.createElement(\'span\');\n      let displayKeyName = keyName;\n      if (keyName === \'liv\') displayKeyName = isFlipped ? \'die (flipped live)\' : \'live\';\n      if (keyName === \'want\') displayKeyName = \'want\';\n      if (keyName === \'think\') displayKeyName = \'think\';\n      if (keyName === \'FLIP\') displayKeyName = \'anti\';\n      \n      text.textContent = `Step ${i+1}: press ${displayKeyName.toUpperCase()}`;\n      text.style.color = i < currentStep ? \'#7fcf9f\' : (i === currentStep ? \'#fff\' : \'#5d626c\');\n      if (i === currentStep) text.style.textDecoration = \'underline\';\n      \n      item.appendChild(check);\n      item.appendChild(text);\n      checklistEl.appendChild(item);\n    });\n  }\n\n  function checkLessonProgress() {\n    if (!sandboxConfig) return;\n    const passed = sandboxConfig.validate(output);\n    \n    if (passed) {\n      document.querySelectorAll(\'.key\').forEach(k => k.classList.remove(\'highlight\'));\n      successBanner.style.display = \'flex\';\n    }\n  }\n\n  // Universal Heuristic English NLP Parser\n  function translateEnglishToAlan(sentence) {\n    const raw = sentence.trim();\n    const text = raw.toLowerCase().replace(/[.,\\\\/#!$%\\\\^&\\\\*;:{}=\\\\-_`~()?]/g,"");\n    const words = text.split(/\\s+/);\n    \n    const map = {\n      "update": "do", "change": "do", "make": "do", "set": "is", "put": "is",\n      "customer": "someone", "user": "someone", "client": "someone", "employee": "someone",\n      "number": "something", "id": "something", "to": "eql", "equal": "eql", "balance": "something",\n      "value": "something", "account": "something"\n    };\n    \n    let currentLineKeys = [];\n    let lineBuilders = [];\n    let currentIndent = 0;\n    \n    for (let i = 0; i < words.length; i++) {\n      const w = words[i];\n      if (!w) continue;\n      \n      if (/^\\d+$/.test(w)) {\n        const digits = w.split(\'\');\n        if (currentLineKeys.length > 0) {\n          currentLineKeys.push("SPACE");\n        }\n        digits.forEach((d) => {\n          currentLineKeys.push(d);\n        });\n        continue;\n      }\n      \n      let handle = map[w];\n      if (!handle) {\n        const standardMap = {\n          "i": "me", "me": "me", "my": "me", "you": "you", "your": "you",\n          "think": "think", "know": "know", "want": "want", "feel": "feel",\n          "see": "see", "hear": "hear", "do": "do", "move": "mov", "live": "liv",\n          "die": "die", "say": "sai", "now": "now", "before": "before", "after": "after",\n          "because": "bik", "place": "place", "here": "place", "not": "not", "dont": "not",\n          "small": "small", "smaller": "small", "tiny": "small", "little": "small",\n          "less": "les", "fewer": "les", "greater": "greater", "larger": "greater",\n          "false": "tru", "no": "not", "incorrect": "not",\n          "left": "right", "below": "above", "outside": "in", "out": "in",\n          "water": "water", "ocean": "water", "sea": "water"\n        };\n        handle = standardMap[w];\n      }\n      \n      if (!handle) {\n        handle = "something";\n      }\n      \n      if (["is", "bik", "if", "eql", "les", "greater", "above", "below", "left", "right", "in", "out"].includes(handle) || w === "set" || w === "update") {\n        if (currentLineKeys.length > 0) {\n          lineBuilders.push({ indent: currentIndent, keys: [...currentLineKeys] });\n          currentLineKeys = [];\n          currentIndent++;\n        }\n      }\n      \n      if (handle === "die") {\n        currentLineKeys.push("FLIP");\n        currentLineKeys.push("liv");\n      } else if (handle === "small") {\n        currentLineKeys.push("FLIP");\n        currentLineKeys.push("big");\n      } else if (handle === "greater") {\n        currentLineKeys.push("FLIP");\n        currentLineKeys.push("les");\n      } else if (handle === "false") {\n        currentLineKeys.push("FLIP");\n        currentLineKeys.push("tru");\n      } else if (w === "left") {\n        currentLineKeys.push("FLIP");\n        currentLineKeys.push("right");\n      } else if (w === "below") {\n        currentLineKeys.push("FLIP");\n        currentLineKeys.push("above");\n      } else if (w === "outside" || w === "out") {\n        currentLineKeys.push("FLIP");\n        currentLineKeys.push("in");\n      } else if (w === "after") {\n        currentLineKeys.push("FLIP");\n        currentLineKeys.push("before");\n      } else {\n        if (currentLineKeys.length > 0 && !["FLIP", "INDENT", "OUTDENT", "DOWN"].includes(handle)) {\n          currentLineKeys.push("SPACE");\n        }\n        currentLineKeys.push(handle);\n      }\n    }\n    \n    if (currentLineKeys.length > 0) {\n      lineBuilders.push({ indent: currentIndent, keys: [...currentLineKeys] });\n    }\n    \n    if (lineBuilders.length === 0) return null;\n    \n    let targetKeys = [];\n    let lastIndent = 0;\n    \n    lineBuilders.forEach((line, idx) => {\n      if (idx > 0) {\n        const diff = line.indent - lastIndent;\n        if (diff > 0) {\n          for (let d = 0; d < diff; d++) targetKeys.push("INDENT");\n        } else if (diff < 0) {\n          for (let d = 0; d < Math.abs(diff); d++) targetKeys.push("OUTDENT");\n        }\n        targetKeys.push("DOWN");\n        lastIndent = line.indent;\n      }\n      targetKeys.push(...line.keys);\n    });\n    \n    const validatorFn = (out) => {\n      const lines = Array.from(out.querySelectorAll(\'.line\'));\n      if (lines.length !== lineBuilders.length) return false;\n      \n      for (let i = 0; i < lineBuilders.length; i++) {\n        const lineEl = lines[i];\n        const targetLine = lineBuilders[i];\n        \n        if (parseInt(lineEl.getAttribute(\'data-indent\') || \'0\', 10) !== targetLine.indent) return false;\n        \n        const elements = Array.from(lineEl.children).filter(el => el.id !== \'cursor\');\n        let elementIdx = 0;\n        \n        for (let k = 0; k < targetLine.keys.length; k++) {\n          const expected = targetLine.keys[k];\n          if (expected === "SPACE") {\n            if (elementIdx >= elements.length || elements[elementIdx].className !== \'spacer\') return false;\n          } else if (expected === "FLIP") {\n            const nextExpected = targetLine.keys[k+1];\n            k++;\n            if (elementIdx >= elements.length) return false;\n            const el = elements[elementIdx];\n            if (el.getAttribute(\'data-handle\') !== nextExpected || el.getAttribute(\'data-flipped\') !== \'true\') return false;\n          } else {\n            if (elementIdx >= elements.length) return false;\n            const el = elements[elementIdx];\n            if (el.getAttribute(\'data-handle\') !== expected) return false;\n          }\n          elementIdx++;\n        }\n        \n        if (elementIdx !== elements.length) return false;\n      }\n      return true;\n    };\n    \n    return {\n      targetKeys: targetKeys,\n      validate: validatorFn,\n      instructions: `Heuristic Translation: <strong>"${sentence}"</strong>.`,\n      hint: `Type the cascading semantic tree: ${targetKeys.filter(k => !["FLIP", "INDENT", "OUTDENT", "DOWN"].includes(k)).join(" -> ").toUpperCase()}`\n    };\n  }\n\n  // Spellcheck & Sandbox Custom Phrase Parser\n  const spellInput = document.getElementById(\'spellcheckInput\');\n  const spellBtn = document.getElementById(\'spellcheckBtn\');\n\n  function handleSpellcheck() {\n    const text = spellInput.value.trim().toLowerCase();\n    if (!text) return;\n\n    const config = translateEnglishToAlan(text);\n\n    if (config) {\n      sandboxConfig = config;\n      \n      // Setup Custom Sandbox Lesson\n      lessonInstructionsEl.innerHTML = sandboxConfig.instructions;\n      lessonHintEl.innerHTML = sandboxConfig.hint;\n      \n      // Display guidance panel\n      guidancePanel.style.display = \'block\';\n      resetWorkspace();\n    }\n  }\n\n  spellBtn.addEventListener(\'click\', handleSpellcheck);\n  spellInput.addEventListener(\'keypress\', (e) => {\n    if (e.key === \'Enter\') handleSpellcheck();\n  });\n\n\n  const keys = document.querySelectorAll(\'.key\');\n\n  keys.forEach(key => {\n    key.addEventListener(\'click\', (e) => {\n      const action = key.getAttribute(\'data-action\');\n      const handle = key.getAttribute(\'data-handle\');\n      \n      const l = sandboxConfig;\n      const target = l ? l.targetKeys[currentStep] : null;\n\n      let pressedId = action || handle;\n\n      // IF IN GUIDED MODE, ENFORCE STRICT CHARACTER-BY-CHARACTER MATCHING!\n      if (l) {\n        if (pressedId === target) {\n          currentStep++;\n        } else if (pressedId === \'BACK\') {\n          // Allow Backspace to undo a step\n          currentStep = Math.max(currentStep - 1, 0);\n        } else {\n          // STRICT KEY-MATCH ENFORCED: Block any wrong keystroke!\n          return;\n        }\n      }\n\n      if (action === \'FLIP\') {\n        isFlipped = !isFlipped;\n        document.querySelectorAll(\'.split-keyboard\').forEach(el => el.classList.toggle(\'flipped\', isFlipped));\n        document.querySelectorAll(\'.key[data-action="FLIP"]\').forEach(el => el.classList.toggle(\'active\', isFlipped));\n        highlightNextKey();\n        updateChecklist();\n        return;\n      }\n\n      if (action === \'INDENT\') {\n        currentIndent = Math.min(currentIndent + 1, 4);\n        activeLine.setAttribute(\'data-indent\', currentIndent);\n        activeLine.style.paddingLeft = `${currentIndent * 40}px`;\n        highlightNextKey();\n        updateChecklist();\n        checkLessonProgress();\n        return;\n      }\n\n      if (action === \'OUTDENT\') {\n        currentIndent = Math.max(currentIndent - 1, 0);\n        activeLine.setAttribute(\'data-indent\', currentIndent);\n        activeLine.style.paddingLeft = `${currentIndent * 40}px`;\n        highlightNextKey();\n        updateChecklist();\n        checkLessonProgress();\n        return;\n      }\n\n      if (action === \'DOWN\') {\n        const newLine = document.createElement(\'div\');\n        newLine.className = \'line\';\n        newLine.setAttribute(\'data-indent\', currentIndent);\n        newLine.style.paddingLeft = `${currentIndent * 40}px`;\n        \n        cursor.remove();\n        newLine.appendChild(cursor);\n        \n        output.appendChild(newLine);\n        activeLine = newLine;\n        output.scrollTop = output.scrollHeight;\n        highlightNextKey();\n        updateChecklist();\n        checkLessonProgress();\n        return;\n      }\n\n      if (action === \'SPACE\') {\n        const spacer = document.createElement(\'div\');\n        spacer.className = \'spacer\';\n        activeLine.insertBefore(spacer, cursor);\n        highlightNextKey();\n        updateChecklist();\n        checkLessonProgress();\n        return;\n      }\n\n      if (action === \'BACK\') {\n        const prev = cursor.previousElementSibling;\n        if (prev) {\n          prev.remove();\n        } else {\n          const prevLine = activeLine.previousElementSibling;\n          if (prevLine) {\n            cursor.remove();\n            prevLine.appendChild(cursor);\n            activeLine.remove();\n            activeLine = prevLine;\n            currentIndent = parseInt(activeLine.getAttribute(\'data-indent\') || \'0\', 10);\n            output.scrollTop = output.scrollHeight;\n          }\n        }\n        highlightNextKey();\n        updateChecklist();\n        checkLessonProgress();\n        return;\n      }\n\n      // Default: typing a symbol\n      let clone = null;\n      let flipType = \'above\';\n\n      // Resolve the SVG template for our direction macros typed from the D-Pad Compass Key\n      if (pressedId === \'above\') {\n        const svgTemplate = `<svg viewBox="0 0 24 24" fill="none" stroke="#e2e8f0" stroke-width="2"><line x1="2" y1="18" x2="22" y2="18" /><polyline points="8,12 12,8 16,12" stroke-width="2" /><line x1="12" y1="8" x2="12" y2="16" stroke-width="2" /><polygon points="12,1 13,3 15,4 13,5 12,7 11,5 9,4 11,3" fill="#e2e8f0" stroke="none" /></svg>`;\n        const parser = new DOMParser();\n        const doc = parser.parseFromString(svgTemplate, \'image/svg+xml\');\n        clone = document.importNode(doc.documentElement, true);\n        flipType = \'below\';\n      } else if (pressedId === \'below\') {\n        const svgTemplate = `<svg viewBox="0 0 24 24" fill="none" stroke="#e2e8f0" stroke-width="2"><line x1="2" y1="18" x2="22" y2="18" /><polyline points="8,12 12,8 16,12" stroke-width="2" /><line x1="12" y1="8" x2="12" y2="16" stroke-width="2" /><polygon points="12,1 13,3 15,4 13,5 12,7 11,5 9,4 11,3" fill="#e2e8f0" stroke="none" /></svg>`;\n        const parser = new DOMParser();\n        const doc = parser.parseFromString(svgTemplate, \'image/svg+xml\');\n        clone = document.importNode(doc.documentElement, true);\n        isFlipped = true; // For below, we force-flip it so the star sits underneath!\n        flipType = \'below\';\n      } else if (pressedId === \'right\') {\n        const svgTemplate = `<svg viewBox="0 0 24 24" fill="none" stroke="#e2e8f0" stroke-width="2"><line x1="4" y1="2" x2="4" y2="22" stroke-width="2" /><polyline points="12,8 16,12 12,16" stroke-width="2" /><line x1="8" y1="12" x2="16" y2="12" stroke-width="2" /><polygon points="20,9 21,11 23,12 21,13 20,15 19,13 17,12 19,11" fill="#e2e8f0" stroke="none" /></svg>`;\n        const parser = new DOMParser();\n        const doc = parser.parseFromString(svgTemplate, \'image/svg+xml\');\n        clone = document.importNode(doc.documentElement, true);\n        flipType = \'left\';\n      } else if (pressedId === \'left\') {\n        const svgTemplate = `<svg viewBox="0 0 24 24" fill="none" stroke="#e2e8f0" stroke-width="2"><line x1="4" y1="2" x2="4" y2="22" stroke-width="2" /><polyline points="12,8 16,12 12,16" stroke-width="2" /><line x1="8" y1="12" x2="16" y2="12" stroke-width="2" /><polygon points="20,9 21,11 23,12 21,13 20,15 19,13 17,12 19,11" fill="#e2e8f0" stroke="none" /></svg>`;\n        const parser = new DOMParser();\n        const doc = parser.parseFromString(svgTemplate, \'image/svg+xml\');\n        clone = document.importNode(doc.documentElement, true);\n        isFlipped = true; // For left, we force-flip it so the star sits to its left!\n        flipType = \'left\';\n      } else if (pressedId === \'in\') {\n        const svgTemplate = `<svg viewBox="0 0 24 24" fill="none" stroke="#e2e8f0" stroke-width="2"><rect x="4" y="6" width="16" height="16" /><polygon points="12,11 13,13 15,14 13,15 12,17 11,15 9,14 11,13" fill="#e2e8f0" stroke="none" /></svg>`;\n        const parser = new DOMParser();\n        const doc = parser.parseFromString(svgTemplate, \'image/svg+xml\');\n        clone = document.importNode(doc.documentElement, true);\n        flipType = \'above\';\n      } else {\n        const svg = key.querySelector(\'svg\');\n        if (svg) {\n          clone = svg.cloneNode(true);\n          flipType = key.getAttribute(\'data-flip\') || \'above\';\n        }\n      }\n\n      if (clone) {\n        // Dynamically add the glowing diacritical star above, below, or to the left of the typed symbol when flipped!\n        if (isFlipped && flipType) {\n          clone.setAttribute(\'data-flipped\', \'true\');\n          \n          // Append the correct diacritical star vector based on layout direction!\n          if (flipType === \'above\') {\n            // Inverted 5-pointed Pentagram Star (Zone 2)\n            const star = document.createElementNS("http://www.w3.org/2000/svg", "polygon");\n            star.setAttribute("fill", "currentColor");\n            star.setAttribute("stroke", "none");\n            star.setAttribute("points", "9,1 12,2.2 15,1 13.8,2.4 16,3.2 13.5,3.8 12,5.5 10.5,3.8 8,3.2 10.2,2.4");\n            clone.appendChild(star);\n          } else if (flipType === \'below\') {\n            // Inverted 5-pointed Pentagram Star (Zone 1 Bottom)\n            const star = document.createElementNS("http://www.w3.org/2000/svg", "polygon");\n            star.setAttribute("fill", "currentColor");\n            star.setAttribute("stroke", "none");\n            star.setAttribute("points", "9,18.5 12,19.7 15,18.5 13.8,19.9 16,20.7 13.5,21.3 12,23.0 10.5,21.3 8,20.7 10.2,19.9");\n            clone.appendChild(star);\n          } else if (flipType === \'left\') {\n            // Sharp 4-pointed Compass Star (Zone 1 Left)\n            const star = document.createElementNS("http://www.w3.org/2000/svg", "polygon");\n            star.setAttribute("fill", "currentColor");\n            star.setAttribute("stroke", "none");\n            star.setAttribute("points", "4,8 5,11 8,12 5,13 4,16 3,13 0,12 3,11");\n            clone.appendChild(star);\n          }\n        }\n        if (targetHandle) {\n          clone.setAttribute(\'data-handle\', targetHandle);\n        }\n        \n        activeLine.insertBefore(clone, cursor);\n        \n        // Auto reset flip after typing\n        isFlipped = false;\n        document.querySelectorAll(\'.split-keyboard\').forEach(el => el.classList.remove(\'flipped\'));\n        document.querySelectorAll(\'.key[data-action="FLIP"]\').forEach(el => el.classList.remove(\'active\'));\n      }\n      \n      highlightNextKey();\n      updateChecklist();\n      checkLessonProgress();\n    });\n  });\n\n  resetWorkspace();\n</script>\n</body>\n</html>\n'

